'use client';

import { useActionState } from 'react';
import { submitContact, type ContactFormState } from '@/app/actions/contact';
import { Button } from '@/components/ui/Button';
import { cn } from '@/lib/utils';

const initial: ContactFormState = { status: 'idle' };

const budgets = [
  'Under $10k',
  '$10k – $25k',
  '$25k – $50k',
  '$50k – $100k',
  '$100k+',
  'Not sure yet',
];

export function ContactForm() {
  const [state, action, pending] = useActionState(submitContact, initial);

  const inputCls = cn(
    'w-full bg-transparent border-b border-white/20 focus:border-[#0000FF] outline-none',
    'font-body text-white placeholder-white/30 py-3 text-base transition-colors duration-200',
  );

  if (state.status === 'success') {
    return (
      <div className="py-16 text-center">
        <p className="font-display text-display-sm text-white uppercase">{state.message}</p>
        <p className="mt-4 font-body text-sm text-white/50">
          We will reach out from our nearest regional office.
        </p>
      </div>
    );
  }

  return (
    <form action={action} noValidate>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div>
          <label htmlFor="name" className="block text-xs font-body font-semibold uppercase tracking-widest text-white/30 mb-2">
            Full Name <span className="text-[#0000FF]">*</span>
          </label>
          <input id="name" name="name" type="text" required autoComplete="name" className={inputCls} placeholder="Your name" />
        </div>

        <div>
          <label htmlFor="email" className="block text-xs font-body font-semibold uppercase tracking-widest text-white/30 mb-2">
            Email <span className="text-[#0000FF]">*</span>
          </label>
          <input id="email" name="email" type="email" required autoComplete="email" className={inputCls} placeholder="you@company.com" />
        </div>

        <div>
          <label htmlFor="company" className="block text-xs font-body font-semibold uppercase tracking-widest text-white/30 mb-2">
            Company
          </label>
          <input id="company" name="company" type="text" autoComplete="organization" className={inputCls} placeholder="Your organisation" />
        </div>

        <div>
          <label htmlFor="budget" className="block text-xs font-body font-semibold uppercase tracking-widest text-white/30 mb-2">
            Budget Range
          </label>
          <select id="budget" name="budget" className={cn(inputCls, 'bg-black')}>
            <option value="">Select budget</option>
            {budgets.map((b) => <option key={b} value={b}>{b}</option>)}
          </select>
        </div>

        <div className="md:col-span-2">
          <label htmlFor="message" className="block text-xs font-body font-semibold uppercase tracking-widest text-white/30 mb-2">
            Tell us about your project <span className="text-[#0000FF]">*</span>
          </label>
          <textarea
            id="message"
            name="message"
            rows={5}
            required
            className={cn(inputCls, 'resize-none')}
            placeholder="Describe your project, goals, and timeline..."
          />
        </div>
      </div>

      {state.status === 'error' && (
        <p role="alert" className="mt-4 font-body text-sm text-red-400">{state.message}</p>
      )}

      <div className="mt-10">
        <Button type="submit" size="lg" disabled={pending}>
          {pending ? 'Sending…' : 'Send Enquiry →'}
        </Button>
      </div>
    </form>
  );
}
